            controller = typeof AbortController !== 'undefined' ? new AbortController() : null;
            crypto.subtle.digest('SHA-256', new TextEncoder().encode(videoId)).then(function (buffer) {
                var bytes = new Uint8Array(buffer);
                var hash = '';
