                for (var i = 0; i < bytes.length; i++) hash += ('0' + bytes[i].toString(16)).slice(-2);
                var query = '?categories=' + encodeURIComponent(JSON.stringify(categoryIds)) +
                    '&actionTypes=' + encodeURIComponent(JSON.stringify(['skip']));
