        var m = Math.floor((sec % 3600) / 60);
        var s = sec % 60;
        var ss = s < 10 ? '0' + s : '' + s;
        if (h > 0) {
            var mm = m < 10 ? '0' + m : '' + m;
            return h + ':' + mm + ':' + ss;
        }
        return m + ':' + ss;
